+        };
+        let report = witness.evaluate_promotion_theorems(&input).unwrap();
+        let events = report.structured_events("t1", "d1", "p1");
+        let failed_event = events
+            .iter()
+            .find(|e| e.outcome == "fail" && e.event.contains("attenuation"))
